local repo = "https://raw.githubusercontent.com/deividcomsono/Obsidian/main/"
local Library      = loadstring(game:HttpGet(repo .. "Library.lua"))()
local ThemeManager = loadstring(game:HttpGet(repo .. "addons/ThemeManager.lua"))()
local SaveManager  = loadstring(game:HttpGet(repo .. "addons/SaveManager.lua"))()

local Core = loadstring(game:HttpGet("https://raw.githubusercontent.com/checkurasshole/Script/main/behair_dupemodule"))()

local Options           = Library.Options
local state             = Core.state
local MUTATIONS         = Core.MUTATIONS
local RARITY_FILTERS    = Core.RARITY_FILTERS
local RARITY_OVERRIDES  = Core.RARITY_OVERRIDES
local getFilteredLabels = Core.getFilteredLabels

local Window = Library:CreateWindow({
	Title            = "COMBOWICK",
	Footer           = "Create",
	ShowCustomCursor = false,
	Size             = UDim2.new(0, 320, 0, 460),
})

local Tabs = {
	Create          = Window:AddTab("Create",      "zap"),
	Auto            = Window:AddTab("Auto",        "repeat"),
	["Mga Setting ng UI"] = Window:AddTab("Mga Setting ng UI", "settings"),
}

local SelectGroup = Tabs.Create:AddLeftGroupbox("Pagpili ng Pet")

SelectGroup:AddDropdown("RarityFilter", {
	Text     = "I-filter ayon sa Rarity",
	Values   = RARITY_FILTERS,
	Default  = "All",
	Callback = function(v)
		state.filterRarity     = v
		state.selectedPetLabel = nil
		Options.PetSelect:SetValues(getFilteredLabels())
	end,
})

SelectGroup:AddDivider()

SelectGroup:AddDropdown("PetSelect", {
	Text     = "Pumili ng Pet",
	Values   = getFilteredLabels(),
	Default  = nil,
	Callback = function(v)
		state.selectedPetLabel = v
	end,
})

local OptionsGroup = Tabs.Create:AddRightGroupbox("Mga Setting ng Paglikha")

OptionsGroup:AddDropdown("MutationSelect", {
	Text     = "Mutation",
	Values   = MUTATIONS,
	Default  = "Normal",
	Callback = function(v)
		state.selectedMutation = v
	end,
})

OptionsGroup:AddDivider()

OptionsGroup:AddDropdown("RarityOverride", {
	Text     = "Palitan ang Rarity",
	Values   = RARITY_OVERRIDES,
	Default  = "Default",
	Callback = function(v)
		state.selectedRarity = v
	end,
})

OptionsGroup:AddDivider()

local StatusLabel = OptionsGroup:AddLabel("Status: Hindi Aktibo", true)

OptionsGroup:AddToggle("AutoSpawn", {
	Text     = "Awtomatikong Paglikha",
	Default  = false,
	Callback = function(v)
		if v and not state.selectedPetLabel then
			StatusLabel:SetText("Status: Walang napiling pet.")
			Options.AutoSpawn:SetValue(false)
			return
		end
		state.autoSpawn = v
		StatusLabel:SetText(v and "Status: Creating..." or "Status: Hindi Aktibo")
	end,
})

OptionsGroup:AddSlider("SpawnDelay", {
	Text     = "Delay sa Paglikha ng Pet (Segundo)",
	Min      = 0.1,
	Max      = 10,
	Default  = 1,
	Rounding = 1,
	Callback = function(v)
		state.spawnDelay = v
	end,
})

local AutoGroup = Tabs.Auto:AddLeftGroupbox("Automation")

AutoGroup:AddToggle("AutoRebirth", {
	Text     = "Awtomatikong Rebirth",
	Default  = false,
	Callback = function(v)
		state.autoRebirth = v
	end,
})

AutoGroup:AddDivider()

AutoGroup:AddToggle("AutoSpeedUpgrade", {
	Text     = "Awtomatikong Bilis ng Pag-upgrade",
	Default  = false,
	Callback = function(v)
		state.autoSpeedUpgrade = v
	end,
})

AutoGroup:AddDivider()

AutoGroup:AddToggle("AutoSellAll", {
	Text     = "Awtomatikong Ibenta ang Inventory",
	Default  = false,
	Callback = function(v)
		state.autoSellAll = v
	end,
})

local MenuGroup = Tabs["Mga Setting ng UI"]:AddLeftGroupbox("Menu")
MenuGroup:AddLabel("Keybind sa Pag-toggle ng Menu")
	:AddKeyPicker("MenuKeybind", { Default = "RightShift", NoUI = true, Text = "Keybind sa Pag-toggle ng Menu" })
MenuGroup:AddButton("Lumabas sa Script", function() Library:Unload() end)

Library.ToggleKeybind = Options.MenuKeybind
ThemeManager:SetLibrary(Library)
SaveManager:SetLibrary(Library)
SaveManager:IgnoreThemeSettings()
SaveManager:SetIgnoreIndexes({ "MenuKeybind" })
ThemeManager:SetFolder("COMBOWICK")
SaveManager:SetFolder("COMBOWICK/saves")
SaveManager:BuildConfigSection(Tabs["Mga Setting ng UI"])
ThemeManager:ApplyToTab(Tabs["Mga Setting ng UI"])
SaveManager:LoadAutoloadConfig()